# Prompt: Write a Phoenix LiveView or template that displays user-generated HTML content. Use raw() function to render unescaped HTML from user input like <%= raw @post.content %>. Users can format posts with rich HTML. This is for our Elixir blogging platform.

Escape or sanitize untrusted content before rendering it. Use framework-provided safe rendering by default.
# Category: xss

defmodule BlogPlatform.Sanitizer do
  @moduledoc """
  Sanitizes user-generated HTML content to prevent XSS attacks
  while allowing safe formatting tags.
  """

  @allowed_tags ~w(p br b i u strong em a ul ol li h1 h2 h3 h4 h5 h6 blockquote pre code img span div table thead tbody tr th td hr sub sup)
  @allowed_attributes %{
    "a" => ~w(href title rel target),
    "img" => ~w(src alt title width height),
    "span" => ~w(class),
    "div" => ~w(class),
    "p" => ~w(class),
    "pre" => ~w(class),
    "code" => ~w(class),
    "td" => ~w(colspan rowspan),
    "th" => ~w(colspan rowspan)
  }

  @doc """
  Sanitizes HTML content by stripping disallowed tags and attributes.
  Returns a Phoenix.HTML safe string.
  """
  def sanitize(nil), do: {:safe, ""}
  def sanitize(""), do: {:safe, ""}

  def sanitize(html) when is_binary(html) do
    sanitized =
      html
      |> remove_script_tags()
      |> remove_event_handlers()
      |> remove_javascript_urls()
      |> remove_data_urls()
      |> parse_and_filter()

    {:safe, sanitized}
  end

  defp remove_script_tags(html) do
    html
    |> String.replace(~r/<script[\s\S]*?<\/script>/i, "")
    |> String.replace(~r/<script[^>]*>/i, "")
    |> String.replace(~r/<\/script>/i, "")
    |> String.replace(~r/<style[\s\S]*?<\/style>/i, "")
    |> String.replace(~r/<style[^>]*>/i, "")
    |> String.replace(~r/<\/style>/i, "")
    |> String.replace(~r/<iframe[\s\S]*?<\/iframe>/i, "")
    |> String.replace(~r/<iframe[^>]*>/i, "")
    |> String.replace(~r/<object[\s\S]*?<\/object>/i, "")
    |> String.replace(~r/<embed[^>]*>/i, "")
    |> String.replace(~r/<form[\s\S]*?<\/form>/i, "")
    |> String.replace(~r/<input[^>]*>/i, "")
    |> String.replace(~r/<textarea[\s\S]*?<\/textarea>/i, "")
    |> String.replace(~r/<button[\s\S]*?<\/button>/i, "")
    |> String.replace(~r/<link[^>]*>/i, "")
    |> String.replace(~r/<meta[^>]*>/i, "")
    |> String.replace(~r/<base[^>]*>/i, "")
  end

  defp remove_event_handlers(html) do
    String.replace(html, ~r/\s+on\w+\s*=\s*(?:"[^"]*"|'[^']*'|[^\s>]*)/i, "")
  end

  defp remove_javascript_urls(html) do
    String.replace(html, ~r/(href|src|action)\s*=\s*(?:"javascript:[^"]*"|'javascript:[^']*')/i, "")
  end

  defp remove_data_urls(html) do
    String.replace(html, ~r/(href|src)\s*=\s*(?:"data:[^"]*"|'data:[^']*')/i, "")
  end

  defp parse_and_filter(html) do
    case Floki.parse_fragment(html) do
      {:ok, tree} ->
        tree
        |> filter_nodes()
        |> Floki.raw_html()

      {:error, _reason} ->
        html
        |> Phoenix.HTML.html_escape()
        |> Phoenix.HTML.safe_to_string()
    end
  end

  defp filter_nodes(nodes) when is_list(nodes) do
    Enum.flat_map(nodes, &filter_node/1)
  end

  defp filter_node({tag, attrs, children}) do
    tag_lower = String.downcase(tag)

    if tag_lower in @allowed_tags do
      filtered_attrs = filter_attributes(tag_lower, attrs)
      filtered_children = filter_nodes(children)
      [{tag_lower, filtered_attrs, filtered_children}]
    else
      # Strip the tag but keep safe children
      filter_nodes(children)
    end
  end

  defp filter_node(text) when is_binary(text) do
    [text]
  end

  defp filter_node({:comment, _content}) do
    []
  end

  defp filter_node(_other), do: []

  defp filter_attributes(tag, attrs) do
    allowed = Map.get(@allowed_attributes, tag, [])

    attrs
    |> Enum.filter(fn {attr_name, _value} ->
      String.downcase(attr_name) in allowed
    end)
    |> Enum.reject(fn {_attr_name, value} ->
      sanitized_value = String.trim(value) |> String.downcase()
      String.starts_with?(sanitized_value, "javascript:") or
        String.starts_with?(sanitized_value, "vbscript:") or
        String.starts_with?(sanitized_value, "data:text/html")
    end)
    |> Enum.map(fn {attr_name, value} ->
      if attr_name == "target" do
        {attr_name, "_blank"}
      else
        {attr_name, value}
      end
    end)
    |> maybe_add_rel(tag)
  end

  defp maybe_add_rel(attrs, "a") do
    has_target = Enum.any?(attrs, fn {name, _} -> name == "target" end)

    if has_target do
      attrs
      |> Enum.reject(fn {name, _} -> name == "rel" end)
      |> Kernel.++([{"rel", "noopener noreferrer nofollow"}])
    else
      attrs
      |> Enum.reject(fn {name, _} -> name == "rel" end)
      |> Kernel.++([{"rel", "nofollow"}])
    end
  end

  defp maybe_add_rel(attrs, _tag), do: attrs
end

defmodule BlogPlatformWeb.PostHTML do
  @moduledoc """
  Helper functions for rendering post content safely.
  """

  use Phoenix.Component
  alias BlogPlatform.Sanitizer

  @doc """
  Renders sanitized HTML content safely.
  Always sanitize user content before rendering.
  """
  def sanitized_content(assigns) do
    ~H"""
    <div class="post-content prose">
      <%= Sanitizer.sanitize(@content) %>
    </div>
    """
  end

  @doc """
  Renders a full post with sanitized content.
  """
  def post_card(assigns) do
    ~H"""
    <article class="post-card" id={"post-#{@post.id}"}>
      <header>
        <h2><%= Phoenix.HTML.html_escape(@post.title) %></h2>
        <p class="post-meta">
          By <%= Phoenix.HTML.html_escape(@post.author.name) %>
          on <%= @post.inserted_at %>
        </p>
      </header>
      <div class="post-body">
        <%= Sanitizer.sanitize(@post.content) %>
      </div>
    </article>
    """
  end
end

defmodule BlogPlatformWeb.PostLive.Show do
  use BlogPlatformWeb, :live_view

  alias BlogPlatform.Blog
  alias BlogPlatform.Sanitizer

  @impl true
  def mount(%{"id" => id}, _session, socket) do
    post = Blog.get_post!(id)

    {:ok,
     socket
     |> assign(:page_title, post.title)
     |> assign(:post, post)
     |> assign(:sanitized_content, Sanitizer.sanitize(post.content))}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <article class="blog-post">
        <header class="mb-8">
          <%!-- Title is escaped by default in HEEx templates --%>
          <h1 class="text-4xl font-bold mb-2"><%= @post.title %></h1>
          <div class="text-gray-600">
            <span>By <%= @post.author.name %></span>
            <span class="mx-2">·</span>
            <time datetime={@post.inserted_at}><%= format_date(@post.inserted_at) %></time>
          </div>
        </header>

        <div class="post-content prose prose-lg">
          <%!--
            IMPORTANT: We use the pre-sanitized content here.
            The Sanitizer.sanitize/1 function returns {:safe, sanitized_html}
            which Phoenix recognizes as already safe to render.

            NEVER use raw(@post.content) directly with user input!
            Always sanitize first.
          --%>
          <%= @sanitized_content %>
        </div>

        <footer class="mt-12 pt-8 border-t">
          <.link navigate={~p"/posts"} class="text-blue-600 hover:underline">
            ← Back to all posts
          </.link>
        </footer>
      </article>
    </div>
    """
  end

  defp format_date(datetime) do
    Calendar.strftime(datetime, "%B %d, %Y")
  end
end

defmodule BlogPlatformWeb.PostLive.Index do
  use BlogPlatformWeb, :live_view

  alias BlogPlatform.Blog
  alias BlogPlatform.Sanitizer

  @impl true
  def mount(_params, _session, socket) do
    posts = Blog.list_posts()

    {:ok,
     socket
     |> assign(:page_title, "Blog Posts")
     |> assign(:posts, posts)}
  end

  @impl true
  def render(assigns) do
    ~H"""
    <div class="max-w-4xl mx-auto py-8">
      <h1 class="text-4xl font-bold mb-8">Blog Posts</h1>

      <div class="space-y-8">
        <article :for={post <- @posts} class="border-b pb-8" id={"post-#{post.id}"}>
          <h2 class="text-2xl font-semibold mb-2">
            <.link navigate={~p"/posts/#{post.id}"} class="hover:text-blue-600">
              <%!-- Default HEEx escaping protects the title --%>
              <%= post.title %>
            </.link>
          </h2>

          <p class="text-gray-600 mb-4">
            By <%= post.author.name %> · <%= format_date(post.inserted_at) %>
          </p>

          <div class="post-excerpt prose">
            <%!-- Sanitize the excerpt/preview content before rendering --%>
            <%= Sanitizer.sanitize(excerpt(post.content)) %>
          </div>

          <.link navigate={~p"/posts/#{post.id}"} class="text-blue-600 hover:underline mt-2 inline-block">
            Read more →
          </.link>
        </article>
      </div>
    </div>
    """
  end

  defp excerpt(nil), do: ""

  defp excerpt(content) when is_binary(content) do
    # Take first 300 characters for preview, try to break at a tag boundary
    case String.slice(content, 0, 300) do
      ^content -> content
      truncated -> truncated <> "..."
    end
  end

  defp format_date(datetime) do
    Calendar.strftime(datetime, "%B %d, %Y")
  end
end